INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"stories"', '"components"', '"vanilla"', '{"demo.css": ".stories {\n  display: grid;\n  grid: 1fr / auto-flow 100%;\n  grid-gap: 1ch;\n  gap: 1ch;\n  overflow-x: auto;\n  scroll-snap-type: x mandatory;\n  overscroll-behavior: contain;\n  touch-action: pan-x;\n}\n\n.user {\n  scroll-snap-align: start;\n  scroll-snap-stop: always;\n  display: grid;\n  grid: [story] 1fr / [story] 1fr;\n}\n\n.story {\n  grid-area: story;\n\n  background-size: cover;\n  background-image: \n    var(--bg), \n    linear-gradient(to top, rgb(249, 249, 249), rgb(226, 226, 226));\n\n  user-select: none;\n  touch-action: manipulation;\n\n  transition: opacity .3s cubic-bezier(0.4, 0.0, 1, 1)\n}\n\n.story.seen {\n  opacity: 0;\n  pointer-events: none;\n}", "demo.html": "<div class=\"stories\"> \n  <section class=\"user\">\n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/480/840);\"></article> \n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/480/841);\"></article>\n  </section>\n  <section class=\"user\">\n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/481/840);\"></article>\n  </section>\n  <section class=\"user\">\n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/481/841);\"></article>\n  </section>\n  <section class=\"user\">\n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/482/840);\"></article>\n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/482/843);\"></article>\n    <article class=\"story\" style=\"--bg: url(https://picsum.photos/482/844);\"></article>\n  </section>\n</div>", "demo.js": "const stories = document.querySelector(''.stories'')\nconst median = stories.offsetLeft + (stories.clientWidth / 2)\n\nconst state = {\n  current_story: stories.firstElementChild.lastElementChild\n}\n\nconst navigateStories = direction => {\n  const story = state.current_story\n  const lastItemInUserStory = story.parentNode.firstElementChild\n  const firstItemInUserStory = story.parentNode.lastElementChild\n  const hasNextUserStory = story.parentElement.nextElementSibling\n  const hasPrevUserStory = story.parentElement.previousElementSibling\n  \n  if (direction === ''next'') {\n    if (lastItemInUserStory === story && !hasNextUserStory)\n      return\n    else if (lastItemInUserStory === story && hasNextUserStory) {\n      state.current_story = story.parentElement.nextElementSibling.lastElementChild\n      story.parentElement.nextElementSibling.scrollIntoView({\n        behavior: ''smooth''\n      })\n    }\n    else {\n      story.classList.add(''seen'')\n      state.current_story = story.previousElementSibling\n    }\n  }\n  else if(direction === ''prev'') {\n    if (firstItemInUserStory === story && !hasPrevUserStory)\n      return\n    else if (firstItemInUserStory === story && hasPrevUserStory) {\n      state.current_story = story.parentElement.previousElementSibling.firstElementChild\n      story.parentElement.previousElementSibling.scrollIntoView({\n        behavior: ''smooth''\n      })\n    }\n    else {\n      story.nextElementSibling.classList.remove(''seen'')\n      state.current_story = story.nextElementSibling\n    }\n  }\n}\n\nstories.addEventListener(''click'', e => {\n  if (e.target.nodeName !== ''ARTICLE'') \n    return\n  \n  navigateStories(\n    e.clientX > median \n      ? ''next'' \n      : ''prev'')\n})\n\n// left & right are free with snap points \ud83d\udc4d\ndocument.addEventListener(''keydown'', ({key}) => {\n  if (key !== ''ArrowDown'' || key !== ''ArrowUp'')\n    navigateStories(\n      key === ''ArrowDown''\n        ? ''next''\n        : ''prev'')\n})"}', '{}', '{"original_path": "patterns/components/stories"}'), ('"svg-favicon"', '"components"', '"vanilla"', '{"demo.css": "", "demo.html": "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 447 428\" width=\"400\" height=\"400\">\n  <style>\n    .favicon-stroke {\n      stroke-width: 8px;\n      stroke: #8929ff;\n    }\n    #skull-outline { fill: white }\n    #eyes-and-nose, #hat-outline { fill: #8929ff }\n    #hat-fill, #hat-bill { fill: #e662e6 }\n\n    @media (prefers-color-scheme: dark) {\n      .favicon-stroke { stroke: #343a40 }\n      #skull-outline { fill: #adb5bd }\n      #hat-outline { fill: #343a40 }\n      #eyes-and-nose { fill: #343a40 }\n    }\n  </style>\n  <g id=\"skull\">\n    <path id=\"skull-outline\" class=\"favicon-stroke\" stroke-linejoin=\"round\" d=\"M19.62 188.39A166.62 166.62 0 0 1 186.24 21.77c115.25 0 166.61 74.59 166.61 166.62 0 1.83-.08 3.64-.13 5.46h.13s.68 175.09.68 178.65c0 30.11-16.26 41.67-36.32 41.67-12.7 0-35.22-3.93-36.22-32.69h-.2c-1 28.76-16.81 32.69-36.22 32.69-18 0-32.87-6.78-35.77-32.53-2.9 25.75-17.8 32.53-35.8 32.53-20.06 0-36.32-11.56-36.32-41.67 0-2.48.36-24.88.36-24.88A166.68 166.68 0 0 1 19.62 188.39Z\" />\n    <path id=\"eyes-and-nose\" d=\"M180.77 205.76c0 23.64 12.84 42.81 28.68 42.81s28.68-19.17 28.68-42.81-12.84-42.82-28.68-42.82-28.68 19.17-28.68 42.82M275 205.76c0 23.64 12.84 42.81 28.68 42.81s28.68-19.17 28.68-42.81-12.84-42.82-28.68-42.82S275 182.11 275 205.76M264.51 276.85s-29.26 43.53-20.12 49.23c7.07 4.41 20.49-16.71 20.49-16.71s12.82 22.58 16.76 20c16.24-10.71-17.13-52.5-17.13-52.5\"/>\n    <path id=\"jawline\" class=\"favicon-stroke\" fill=\"none\" stroke-linecap=\"round\" d=\"M114.92 284.33c22.54-1 22 7 22 62.48\" />\n  </g>\n  <g id=\"hat\">\n    <path id=\"hat-fill\" d=\"m36.27 118.44 2-5.41c.37-1 9.25-24.14 33-47.53 21.83-21.56 60.88-47.26 122.91-47.26C258 18.24 294.8 44 314.46 65.65c21.38 23.52 27.49 46.82 27.74 47.8l1.27 5Z\"/>\n    <path id=\"hat-outline\" d=\"M194.17 22.24c120.68 0 144.15 92.2 144.15 92.2H42.05s34.67-92.2 152.12-92.2m0-8c-27.9 0-53.65 5.07-76.52 15.08a162.3 162.3 0 0 0-49.21 33.33c-24.31 24-33.5 48-33.88 49l-4.07 10.82h318.13l-2.54-10c-.26-1-6.62-25.26-28.66-49.51a140.29 140.29 0 0 0-46.52-33.6c-22.25-10-48.06-15.12-76.73-15.12\"/>\n    <path id=\"hat-bill\" class=\"favicon-stroke\" stroke-linecap=\"square\" d=\"M350.7 117.76c69.17 0 112.9-106.93 57.6-106.93-81 0-95.18 74.6-198.47 106.93M80.32 117.86h267.53\"/>\n  </g>\n</svg>", "demo.js": ""}', '{}', '{"original_path": "patterns/components/svg-favicon"}'), ('"switch"', '"components"', '"vanilla"', '{"demo.css": ".gui-switch {\n  --thumb-size: 2rem;\n  --thumb: hsl(0 0% 100%);\n  --thumb-highlight: hsl(0 0% 0% / 25%);\n  \n  --track-size: calc(var(--thumb-size) * 2);\n  --track-padding: 2px;\n  --track-inactive: hsl(80 0% 80%);\n  --track-active: hsl(80 60% 45%);\n\n  --thumb-color: var(--thumb);\n  --thumb-color-highlight: var(--thumb-highlight);\n  --track-color-inactive: var(--track-inactive);\n  --track-color-active: var(--track-active);\n\n  --isLTR: 1;\n\n  display: flex;\n  align-items: center;\n  gap: 2ch;\n  justify-content: space-between;\n\n  cursor: pointer;\n  user-select: none;\n  -webkit-tap-highlight-color: transparent;\n\n  @media (prefers-color-scheme: dark) {\n    --thumb: hsl(0 0% 5%);\n    --thumb-highlight: hsl(0 0% 100% / 25%);\n    --track-inactive: hsl(80 0% 35%);\n    --track-active: hsl(80 60% 60%);\n  }\n\n  &:dir(rtl) {\n    --isLTR: -1;\n  }\n\n  &.-vertical {\n    min-block-size: calc(var(--track-size) + calc(var(--track-padding) * 2));\n\n    & > input {\n      transform: rotate(calc(90deg * var(--isLTR) * -1));\n      touch-action: pan-x;\n    }\n  }\n\n  & > input {\n    --thumb-position: 0%;\n    --thumb-transition-duration: .25s;\n    \n    padding: var(--track-padding);\n    background: var(--track-color-inactive);\n    inline-size: var(--track-size);\n    block-size: var(--thumb-size);\n    border-radius: var(--track-size);\n\n    appearance: none;\n    pointer-events: none;\n    touch-action: pan-y;\n    border: none;\n    outline-offset: 5px;\n    box-sizing: content-box;\n\n    flex-shrink: 0;\n    display: grid;\n    align-items: center;\n    grid: [track] 1fr / [track] 1fr;\n\n    transition: background-color .25s ease;\n\n    &::before {\n      --highlight-size: 0;\n\n      content: \"\";\n      cursor: pointer;\n      pointer-events: auto;\n      grid-area: track;\n      inline-size: var(--thumb-size);\n      block-size: var(--thumb-size);\n      background: var(--thumb-color);\n      box-shadow: 0 0 0 var(--highlight-size) var(--thumb-color-highlight);\n      border-radius: 50%;\n      transform: translateX(var(--thumb-position));\n\n      @media (--motionOK) { & {\n        transition: \n          transform var(--thumb-transition-duration) ease,\n          box-shadow .25s ease;\n      }}\n    }\n\n    &:not(:disabled):hover::before {\n      --highlight-size: .5rem;\n    }\n\n    &:checked {\n      background: var(--track-color-active);\n      --thumb-position: calc((var(--track-size) - 100%) * var(--isLTR));\n    }\n\n    &:indeterminate {\n      --thumb-position: calc(\n        calc(calc(var(--track-size) / 2) - calc(var(--thumb-size) / 2))\n        * var(--isLTR)\n      );\n    }\n\n    &:disabled {\n      cursor: not-allowed;\n      --thumb-color: transparent;\n\n      &::before {\n        cursor: not-allowed;\n        box-shadow: inset 0 0 0 2px hsl(0 0% 100% / 50%);\n\n        @media (prefers-color-scheme: dark) {\n          box-shadow: inset 0 0 0 2px hsl(0 0% 0% / 50%);\n        }\n      }\n    }\n  }\n}", "demo.html": "<label for=\"switch-1\" class=\"gui-switch\">\n  Default\n  <input type=\"checkbox\" role=\"switch\" id=\"switch-1\">\n</label>\n\n<label for=\"switch-2\" class=\"gui-switch\">\n  Indeterminate\n  <input type=\"checkbox\" role=\"switch\" id=\"switch-2\">\n  <script>document.getElementById(''switch-2'').indeterminate = true</script>\n</label>\n\n<label for=\"switch-3\" class=\"gui-switch\">\n  Disabled\n  <input type=\"checkbox\" role=\"switch\" id=\"switch-3\" disabled>\n</label>\n\n<label for=\"switch-4\" class=\"gui-switch\">\n  Disabled (checked)\n  <input type=\"checkbox\" role=\"switch\" id=\"switch-4\" disabled checked>\n</label>\n\n<label for=\"switch-vertical\" class=\"gui-switch -vertical\">\n  Vertical\n  <input type=\"checkbox\" role=\"switch\" id=\"switch-vertical\">\n</label>", "demo.js": "const elements = document.querySelectorAll(''.gui-switch'')\nconst switches = new WeakMap()\n\nconst state = {\n  activethumb: null,\n  recentlyDragged: false,\n}\n\nconst getStyle = (element, prop) =>\n  parseInt(\n    window.getComputedStyle(element)\n      .getPropertyValue(prop))\n\nconst getPseudoStyle = (element, prop) =>\n  parseInt(\n    window.getComputedStyle(element, '':before'')\n      .getPropertyValue(prop))\n\nconst dragInit = event => {\n  if (event.target.disabled) return\n\n  state.activethumb = event.target\n  state.activethumb.addEventListener(''pointermove'', dragging)\n  state.activethumb.style.setProperty(''--thumb-transition-duration'', ''0s'')\n}\n\nconst dragging = event => {\n  if (!state.activethumb) return\n\n  let {thumbsize, bounds, padding} = switches.get(state.activethumb.parentElement)\n  let directionality = getStyle(state.activethumb, ''--isLTR'')\n\n  let track = (directionality === -1)\n    ? (state.activethumb.clientWidth * -1) + thumbsize + padding\n    : 0\n\n  let pos = Math.round(event.offsetX - thumbsize / 2)\n\n  if (pos < bounds.lower) pos = 0\n  if (pos > bounds.upper) pos = bounds.upper\n\n  state.activethumb.style.setProperty(''--thumb-position'', `${track + pos}px`)\n}\n\nconst dragEnd = event => {\n  if (!state.activethumb) return\n\n  state.activethumb.checked = determineChecked()\n\n  if (state.activethumb.indeterminate)\n    state.activethumb.indeterminate = false\n\n  state.activethumb.style.removeProperty(''--thumb-transition-duration'')\n  state.activethumb.style.removeProperty(''--thumb-position'')\n  state.activethumb.removeEventListener(''pointermove'', dragging)\n  state.activethumb = null\n\n  padRelease()\n}\n\nconst padRelease = () => {\n  state.recentlyDragged = true\n\n  setTimeout(_ => {\n    state.recentlyDragged = false\n  }, 300)\n}\n\nconst preventBubbles = event => {\n  if (state.recentlyDragged)\n    event.preventDefault() && event.stopPropagation()\n}\n\nconst labelClick = event => {\n  if (\n    state.recentlyDragged || \n    !event.target.classList.contains(''gui-switch'') || \n    event.target.querySelector(''input'').disabled\n  ) return\n\n  let checkbox = event.target.querySelector(''input'')\n  checkbox.checked = !checkbox.checked\n  event.preventDefault()\n}\n\nconst determineChecked = () => {\n  let {bounds} = switches.get(state.activethumb.parentElement)\n  let curpos = \n    Math.abs(\n      parseInt(\n        state.activethumb.style.getPropertyValue(''--thumb-position'')))\n\n  if (!curpos) {\n    curpos = state.activethumb.checked\n      ? bounds.lower\n      : bounds.upper\n  }\n\n  return curpos >= bounds.middle\n}\n\nelements.forEach(guiswitch => {\n  let checkbox = guiswitch.querySelector(''input'')\n  let thumbsize = getPseudoStyle(checkbox, ''width'')\n  let padding = getStyle(checkbox, ''padding-left'') + getStyle(checkbox, ''padding-right'')\n\n  checkbox.addEventListener(''pointerdown'', dragInit)\n  checkbox.addEventListener(''pointerup'', dragEnd)\n  checkbox.addEventListener(''click'', preventBubbles)\n  guiswitch.addEventListener(''click'', labelClick)\n\n  switches.set(guiswitch, {\n    thumbsize,\n    padding,\n    bounds: {\n      lower: 0,\n      middle: (checkbox.clientWidth - padding) / 4,\n      upper: checkbox.clientWidth - thumbsize - padding,\n    },\n  })\n})\n\nwindow.addEventListener(''pointerup'', event => {\n  if (!state.activethumb) return\n\n  dragEnd(event)\n})"}', '{}', '{"original_path": "patterns/components/switch"}'), ('"tabs"', '"components"', '"vanilla"', '{"demo.css": "snap-tabs {\n  --hue: 328deg;\n  --accent: var(--hue) 100% 54%;\n  --indicator-size: 2px;\n\n  --space-1: .5rem;\n  --space-2: 1rem;\n  --space-3: 1.5rem;\n  \n  display: flex;\n  flex-direction: column;\n\n  overflow: hidden;\n  position: relative;\n\n  & :matches(header, nav, section, article, a) {\n    outline-color: hsl(var(--accent));\n    outline-offset: -5px;\n  }\n}\n\n.scroll-snap-x {\n  overflow: auto hidden;\n  overscroll-behavior-x: contain;\n  scroll-snap-type: x mandatory;\n\n  @media (prefers-reduced-motion: no-preference) {\n    scroll-behavior: smooth;\n  }\n  \n  @media (hover: none) {\n    scrollbar-width: none;\n\n    &::-webkit-scrollbar {\n      width: 0;\n      height: 0;\n    }\n  }\n}\n\nsnap-tabs > header {\n  --text-color: hsl(var(--hue) 5% 40%);\n  --text-active-color: hsl(var(--hue) 20% 10%);\n\n  flex-shrink: 0;\n  min-block-size: fit-content;\n\n  display: flex;\n  flex-direction: column;\n\n  & > nav {\n    display: flex;\n  }\n\n  & a {\n    scroll-snap-align: start;\n\n    display: inline-flex;\n    align-items: center;\n    white-space: nowrap;\n\n    font-size: .8rem;\n    color: var(--text-color);\n    font-weight: bold;\n    text-decoration: none;\n    padding: var(--space-2) var(--space-3);\n\n    & > svg {\n      inline-size: 1.5em;\n      pointer-events: none;\n    }\n\n    &:hover {\n      background: hsl(var(--accent) / 5%);\n    }\n\n    &:focus {\n      outline-offset: -.5ch;\n    }\n  }\n\n  & > .snap-indicator {\n    inline-size: 0;\n    block-size: var(--indicator-size);\n    border-radius: var(--indicator-size);\n    background: hsl(var(--accent));\n  }\n}\n\nsnap-tabs > section {\n  block-size: 100%;\n\n  display: grid;\n  grid-auto-flow: column;\n  grid-auto-columns: 100%;\n\n  & > article {\n    scroll-snap-align: start;\n    overflow-y: auto;\n    overscroll-behavior-y: contain;\n\n    padding: var(--space-2) var(--space-3);\n  }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  /* \n    - swap to border-bottom styles\n    - transition colors\n    - hide the animated .indicator \n  */\n\n  snap-tabs {\n    & > header a {\n      border-block-end: var(--indicator-size) solid hsl(var(--accent) / 0%);\n      transition:\n        color .7s ease,\n        border-color .5s ease;\n\n      &:matches(:target,:active,[active]) {\n        color: var(--text-active-color);\n        border-block-end-color: hsl(var(--accent));\n      }\n    }\n\n    & .snap-indicator {\n      visibility: hidden;\n    }\n  }\n}", "demo.html": "<snap-tabs>\n  <header class=\"scroll-snap-x\"> \n    <nav>\n      <a active href=\"#responsive\">Responsive</a>\n      <a href=\"#accessible\">Accessible</a>\n      <a href=\"#overscroll\">Horizontal Overscroll Ready</a>\n      <a href=\"#more\"><!-- ...SVG icon --></a>\n    </nav>\n    <span class=\"snap-indicator\"></span>\n  </header>\n  <section class=\"scroll-snap-x\">\n    <article id=\"responsive\">\n      <!-- ...content -->\n    </article>\n    <article id=\"accessible\">\n      <!-- ...content -->\n    </article>\n    <article id=\"overscroll\">\n      <!-- ...content -->\n    </article>\n    <article id=\"more\">\n      <!-- ...content -->\n    </article>\n  </section>\n</snap-tabs>", "demo.js": "import ''https://argyleink.github.io/scroll-timeline/dist/scroll-timeline.js''\n\nconst {matches:motionOK} = window.matchMedia(\n  ''(prefers-reduced-motion: no-preference)''\n)\n\n// grab and stash elements\nconst tabgroup     = document.querySelector(''snap-tabs'')\nconst tabsection   = tabgroup.querySelector('':scope > section'')\nconst tabnav       = tabgroup.querySelector('':scope nav'')\nconst tabnavitems  = tabnav.querySelectorAll('':scope a'')\nconst tabindicator = tabgroup.querySelector('':scope .snap-indicator'')\n\n/* \n  shared timeline for .indicator \n  and nav > a colors */\nconst sectionScrollTimeline = new ScrollTimeline({\n  scrollSource: tabsection,\n  orientation: ''inline'',\n  fill: ''both'',\n})\n\n/*\n  for each nav link\n  - animate color based on the scroll timeline\n  - color is active when its the current index*/\ntabnavitems.forEach(navitem => {\n  navitem.animate({\n      color: [...tabnavitems].map(item => \n        item === navitem\n          ? `var(--text-active-color)`\n          : `var(--text-color)`)\n    }, {\n      duration: 1000,\n      fill:     ''both'',\n      timeline: sectionScrollTimeline,\n    }\n  )\n})\n\nif (motionOK) {\n  tabindicator.animate({ \n      transform: [...tabnavitems].map(({offsetLeft}) => \n        `translateX(${offsetLeft}px)`),\n      width: [...tabnavitems].map(({offsetWidth}) => \n        `${offsetWidth}px`)\n    }, {\n      duration: 1000,\n      fill:     ''both'',\n      timeline: sectionScrollTimeline,\n    }\n  )\n}\n\nconst setActiveTab = tabbtn => {\n  tabnav\n    .querySelector('':scope a[active]'')\n    .removeAttribute(''active'')\n  \n  tabbtn.setAttribute(''active'', '''')\n  tabbtn.scrollIntoView()\n}\n \nconst determineActiveTabSection = () => {\n  const i = tabsection.scrollLeft / tabsection.clientWidth\n  const matchingNavItem = tabnavitems[i]\n  \n  matchingNavItem && setActiveTab(matchingNavItem)\n}\n\ntabnav.addEventListener(''click'', e => {\n  if (e.target.nodeName !== \"A\") return\n  setActiveTab(e.target)\n})\n\ntabsection.addEventListener(''scroll'', () => {\n  clearTimeout(tabsection.scrollEndTimer)               \n  tabsection.scrollEndTimer = setTimeout(\n    determineActiveTabSection\n  , 100)\n})\n\nwindow.onload = () => {\n  if (location.hash)\n    tabsection.scrollLeft = document\n      .querySelector(location.hash)\n      .offsetLeft\n    \n  determineActiveTabSection()\n}"}', '{}', '{"original_path": "patterns/components/tabs"}'), ('"toast"', '"components"', '"vanilla"', '{"demo.css": ".gui-toast-group {\n  position: fixed;\n  z-index: 1;\n  inset-block-end: 0;\n  inset-inline: 0;\n  padding-block-end: 5vh;\n\n  display: grid;\n  justify-items: center;\n  justify-content: center;\n  gap: 1vh;\n\n  /* optimizations */\n  pointer-events: none;\n}\n\n.gui-toast {\n  --_duration: 3s;\n  --_bg-lightness: 90%;\n  --_travel-distance: 0;\n\n  font-family: system-ui, sans-serif;\n  color: black;\n  background: hsl(0 0% var(--_bg-lightness) / 90%);\n  \n  max-inline-size: min(25ch, 90vw);\n  padding-block: .5ch;\n  padding-inline: 1ch;\n  border-radius: 3px;\n  font-size: 1rem;\n\n  will-change: transform;\n  animation: \n    fade-in .3s ease,\n    slide-in .3s ease,\n    fade-out .3s ease var(--_duration);\n\n  @media (--dark) {\n    color: white;\n    --_bg-lightness: 20%;\n  }\n\n  @media (--motionOK) {\n    --_travel-distance: 5vh;\n  }\n}\n\n@keyframes fade-in {\n  from { opacity: 0 }\n}\n\n@keyframes fade-out {\n  to { opacity: 0 }\n}\n\n@keyframes slide-in {\n  from { transform: translateY(var(--_travel-distance, 10px)) }\n}\n", "demo.html": "<button id=\"spells\">\n  Cast Spell\n</button>\n<button id=\"actions\">\n  Mock User Action\n</button>", "demo.js": "const init = () => {\n  const node = document.createElement(''section'')\n  node.classList.add(''gui-toast-group'')\n\n  document.firstElementChild.insertBefore(node, document.body)\n  return node\n}\n\nconst createToast = text => {\n  const node = document.createElement(''output'')\n  \n  node.innerText = text\n  node.classList.add(''gui-toast'')\n  node.setAttribute(''role'', ''status'')\n  node.setAttribute(''aria-live'', ''polite'')\n\n  return node\n}\n\nconst addToast = toast => {\n  const { matches:motionOK } = window.matchMedia(\n    ''(prefers-reduced-motion: no-preference)''\n  )\n\n  Toaster.children.length && motionOK\n    ? flipToast(toast)\n    : Toaster.appendChild(toast)\n}\n\nconst Toast = text => {\n  let toast = createToast(text)\n  addToast(toast)\n\n  return new Promise(async (resolve, reject) => {\n    await Promise.allSettled(\n      toast.getAnimations().map(animation => \n        animation.finished\n      )\n    )\n    Toaster.removeChild(toast)\n    resolve() \n  })\n}\n\n// https://aerotwist.com/blog/flip-your-animations/\nconst flipToast = toast => {\n  // FIRST\n  const first = Toaster.offsetHeight\n\n  // add new child to change container size\n  Toaster.appendChild(toast)\n\n  // LAST\n  const last = Toaster.offsetHeight\n\n  // INVERT\n  const invert = last - first\n\n  // PLAY\n  const animation = Toaster.animate([\n    { transform: `translateY(${invert}px)` },\n    { transform: ''translateY(0)'' }\n  ], {\n    duration: 150,\n    easing: ''ease-out'',\n  })\n\n  animation.startTime = document.timeline.currentTime\n}\n\nconst Toaster = init()\nexport default Toast"}', '{}', '{"original_path": "patterns/components/toast"}'), ('"example-pattern"', '"example-set"', '"vanilla"', '{"demo.css": "body {\n  background-color: red;\n}", "demo.html": "<div>\n  HTML for the example-pattern\n</div>", "demo.js": "console.log(''Javascript for the example-pattern'');\ndocument.body.append(''Javascript for the example-pattern'');\n"}', '{}', '{"original_path": "patterns/example-set/example-pattern"}'), ('"full-html-demo"', '"example-set"', '"vanilla"', '{"demo (2).js": "console.log(''I am a special script declared as a static asset of this demo.'');\n\n/**\n * This file is ignored and not automatically included inside \"demo.html\",\n * because this pattern demo is defined as a standalone, full HTML page.\n */\n", "demo.css": "body {\n  background-color: red;\n}\n\n/* This CSS is displayed in the samples area of a CodePattern.\nIt is ignored and not included in the demo.html, because in this pattern demo\nis defined as a standalone, full html page. */", "demo.html": "<div>\n  This HTML is displayed as source code in the samples area of a CodePattern.\n  It is ignored and not included in \"demo.html\", because this pattern demo is\n  defined as a standalone, full HTML page.\n</div>", "demo.js": "console.log(''This JS is displayed in the samples area of a CodePattern.'');\n\n/**\n * This file is ignored and not automatically included inside \"demo.html\",\n * because this pattern demo is defined as a standalone, full HTML page.\n */\n"}', '{}', '{"original_path": "patterns/example-set/full-html-demo"}'), ('"graph"', '"example-set"', '"vanilla"', '{"demo.css": ".highcharts-figure,\n.highcharts-data-table table {\n    min-width: 320px;\n    max-width: 800px;\n 