",\n              61\n          ],\n          [\n              \"MODX\",\n              \"WordPress\",\n              58\n          ],\n          [\n              \"SPIP\",\n              \"WordPress\",\n              57\n          ],\n          [\n              \"1C-Bitrix\",\n              \"Tilda\",\n              57\n          ],\n          [\n              \"WordPress\",\n              \"Sitecore\",\n              56\n          ],\n          [\n              \"TYPO3 CMS\",\n              \"Drupal\",\n              54\n          ],\n          [\n              \"Microsoft SharePoint\",\n              \"Drupal\",\n              52\n          ],\n          [\n              \"Drupal\",\n              \"1C-Bitrix\",\n              51\n          ]\n        ],\n        type: ''dependencywheel'',\n        name: ''CMS churn'',\n        dataLabels: {\n            color: ''#333'',\n            textPath: {\n                enabled: true,\n                attributes: {\n                    dy: 5\n                }\n            },\n            distance: 10\n        },\n        size: ''95%''\n    }]\n  });\n});\n"}', '{}', '{"original_path": "patterns/example-set/graph"}'), ('"drag-and-drop-directories"', '"files"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  line-height: 1.5;\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n}\n\nimg,\nvideo {\n  height: auto;\n  max-width: 100%;\n}\n\nmain {\n  flex-grow: 1;\n}\n\nfooter {\n  margin-top: 1rem;\n  border-top: solid CanvasText 1px;\n  font-size: 0.8rem;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>How to drag and drop directories</title>\n  </head>\n  <body>\n    <main>\n      <h1>How to drag and drop directories</h1>\n      <p>Drag and drop one or multiple files or directories onto the page.</p>\n      <pre></pre>\n    </main>\n  </body>\n</html>\n", "demo.js": "const supportsFileSystemAccessAPI =\n  \"getAsFileSystemHandle\" in DataTransferItem.prototype;\nconst supportsWebkitGetAsEntry =\n  \"webkitGetAsEntry\" in DataTransferItem.prototype;\n\nconst elem = document.querySelector(\"main\");\nconst debug = document.querySelector(\"pre\");\n\nelem.addEventListener(\"dragover\", (e) => {\n  // Prevent navigation.\n  e.preventDefault();\n});\n\nelem.addEventListener(\"dragenter\", (e) => {\n  elem.style.outline = \"solid red 1px\";\n});\n\nelem.addEventListener(\"dragleave\", (e) => {\n  elem.style.outline = \"\";\n});\n\nelem.addEventListener(\"drop\", async (e) => {\n  e.preventDefault();\n  elem.style.outline = \"\";\n  const fileHandlesPromises = [...e.dataTransfer.items]\n    .filter((item) => item.kind === \"file\")\n    .map((item) =>\n      supportsFileSystemAccessAPI\n        ? item.getAsFileSystemHandle()\n        : supportsWebkitGetAsEntry\n        ? item.webkitGetAsEntry()\n        : item.getAsFile()\n    );\n\n  for await (const handle of fileHandlesPromises) {\n    if (handle.kind === \"directory\" || handle.isDirectory) {\n      console.log(`Directory: ${handle.name}`);\n      debug.textContent += `Directory: ${handle.name}\\n`;\n    } else {\n      console.log(`File: ${handle.name}`);\n      debug.textContent += `File: ${handle.name}\\n`;\n    }\n  }\n});\n"}', '{}', '{"original_path": "patterns/files/drag-and-drop-directories"}'), ('"drag-and-drop-files"', '"files"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  line-height: 1.5;\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n}\n\nimg,\nvideo {\n  height: auto;\n  max-width: 100%;\n}\n\nmain {\n  flex-grow: 1;\n}\n\nfooter {\n  margin-top: 1rem;\n  border-top: solid CanvasText 1px;\n  font-size: 0.8rem;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>How to drag and drop files</title>\n  </head>\n  <body>\n    <main>\n      <h1>How to drag and drop files</h1>\n      <p>Drag and drop one or multiple files onto the page.</p>\n      <pre></pre>\n    </main>\n  </body>\n</html>\n", "demo.js": "const supportsFileSystemAccessAPI =\n  \"getAsFileSystemHandle\" in DataTransferItem.prototype;\nconst supportsWebkitGetAsEntry =\n  \"webkitGetAsEntry\" in DataTransferItem.prototype;\n\nconst elem = document.querySelector(\"main\");\nconst debug = document.querySelector(\"pre\");\n\nelem.addEventListener(\"dragover\", (e) => {\n  // Prevent navigation.\n  e.preventDefault();\n});\n\nelem.addEventListener(\"dragenter\", (e) => {\n  elem.style.outline = \"solid red 1px\";\n});\n\nelem.addEventListener(\"dragleave\", (e) => {\n  elem.style.outline = \"\";\n});\n\nelem.addEventListener(\"drop\", async (e) => {\n  e.preventDefault();\n  elem.style.outline = \"\";\n  const fileHandlesPromises = [...e.dataTransfer.items]\n    .filter((item) => item.kind === \"file\")\n    .map((item) =>\n      supportsFileSystemAccessAPI\n        ? item.getAsFileSystemHandle()\n        : supportsWebkitGetAsEntry\n        ? item.webkitGetAsEntry()\n        : item.getAsFile()\n    );\n\n  for await (const handle of fileHandlesPromises) {\n    if (handle.kind === \"directory\" || handle.isDirectory) {\n      console.log(`Directory: ${handle.name}`);\n      debug.textContent += `Directory: ${handle.name}\\n`;\n    } else {\n      console.log(`File: ${handle.name}`);\n      debug.textContent += `File: ${handle.name}\\n`;\n    }\n  }\n});\n"}', '{}', '{"original_path": "patterns/files/drag-and-drop-files"}'), ('"handle-files-opened-from-the-file-explorer"', '"files"', '"vanilla"', '{"demo.css": "html {\n  box-sizing: border-box;\n  font-family: system-ui, sans-serif;\n  color-scheme: dark light;\n}\n\n*, *:before, *:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n}\n\nimg {\n  height: auto;\n  max-width: 100%;\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link rel=\"manifest\" href=\"manifest.json\" />\n    <title>How to handle files opened from the file explorer</title>\n    <link rel=\"stylesheet\" href=\"style.css\" />\n    <script>\n      if (''serviceWorker'' in navigator) {\n        window.addEventListener(''load'', async () => {\n          const registration = await navigator.serviceWorker.register(\n            ''sw.js'',\n          );\n          console.log(\n            ''Service worker registered for scope'',\n            registration.scope,\n          );\n        });\n      }\n    </script>\n    <script src=\"script.js\" type=\"module\"></script>\n  </head>\n  <body>\n    <h1>How to handle files opened from the file explorer</h1>\n    <p>Install the app. After the installation, try opening an image file from the file explorer with the app.\n  </body>\n</html>\n", "demo.js": "if (''launchQueue'' in window && ''files'' in LaunchParams.prototype) {\n  launchQueue.setConsumer((launchParams) => {\n    if (!launchParams.files.length) {\n      return;\n    }\n    for (const fileHandle of launchParams.files) {\n      document.body.innerHTML += `<p>${fileHandle.name}</p>`;\n    }\n  });\n}", "demo.json": "{\n  \"name\": \"How to handle files opened from the file explorer\",\n  \"short_name\": \"Handle files\",\n  \"start_url\": \"../demo.html\",\n  \"id\": \"../demo.html\",\n  \"icons\": [\n    {\n      \"src\": \"../assets/favicon.png\",\n      \"type\": \"image/png\",\n      \"sizes\": \"512x512\"\n    },\n    {\n     