\"76\"/><line x1=\"-32\" x2=\"160\" y1=\"80\" y2=\"80\"/><line x1=\"-32\" x2=\"160\" y1=\"84\" y2=\"84\"/><line x1=\"-32\" x2=\"160\" y1=\"88\" y2=\"88\"/><line x1=\"-32\" x2=\"160\" y1=\"92\" y2=\"92\"/><line x1=\"-32\" x2=\"160\" y1=\"96\" y2=\"96\"/><line x1=\"-32\" x2=\"160\" y1=\"100\" y2=\"100\"/><line x1=\"-32\" x2=\"160\" y1=\"104\" y2=\"104\"/><line x1=\"-32\" x2=\"160\" y1=\"108\" y2=\"108\"/><line x1=\"-32\" x2=\"160\" y1=\"112\" y2=\"112\"/><line x1=\"-32\" x2=\"160\" y1=\"116\" y2=\"116\"/><line x1=\"-32\" x2=\"160\" y1=\"120\" y2=\"120\"/><line x1=\"-32\" x2=\"160\" y1=\"124\" y2=\"124\"/><line x1=\"-32\" x2=\"160\" y1=\"128\" y2=\"128\"/><line x1=\"-32\" x2=\"160\" y1=\"132\" y2=\"132\"/><line x1=\"-32\" x2=\"160\" y1=\"136\" y2=\"136\"/><line x1=\"-32\" x2=\"160\" y1=\"140\" y2=\"140\"/><line x1=\"-32\" x2=\"160\" y1=\"144\" y2=\"144\"/><line x1=\"-32\" x2=\"160\" y1=\"148\" y2=\"148\"/><line x1=\"-32\" x2=\"160\" y1=\"152\" y2=\"152\"/><line x1=\"-32\" x2=\"160\" y1=\"156\" y2=\"156\"/></g><path d=\"m159.75-31.75v191.5h-191.5v-191.5h191.5m0.25-0.25h-192v192h192v-192z\"/></g></g><g fill=\"#F44336\"><rect width=\"4\" height=\"128\" opacity=\".3\"/><rect x=\"124\" width=\"4\" height=\"128\" opacity=\".3\"/><rect transform=\"matrix(-1.837e-16 1 -1 -1.837e-16 66 -62)\" x=\"62\" y=\"-58\" width=\"4\" height=\"120\" opacity=\".3\"/><rect transform=\"matrix(-1.837e-16 1 -1 -1.837e-16 190 62)\" x=\"62\" y=\"66\" width=\"4\" height=\"120\" opacity=\".3\"/></g></g></g></svg>\n"}', '{}', '{"original_path": "patterns/files/handle-files-opened-from-the-file-explorer"}'), ('"open-a-directory"', '"files"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83d\udcc2</text></svg>\"\n    />\n    <title>How to open a directory</title>\n  </head>\n  <body>\n    <h1>How to open a directory</h1>\n    <button type=\"button\">Open directory</button>\n    <pre></pre>\n  </body>\n</html>\n", "demo.js": "const button = document.querySelector(''button'');\nconst pre = document.querySelector(''pre'');\n\nconst openDirectory = async (mode = \"read\") => {\n  // Feature detection. The API needs to be supported\n  // and the app not run in an iframe.\n  const supportsFileSystemAccess =\n    \"showDirectoryPicker\" in window &&\n    (() => {\n      try {\n        return window.self === window.top;\n      } catch {\n        return false;\n      }\n    })();\n  // If the File System Access API is supported\u2026\n  if (supportsFileSystemAccess) {\n    let directoryStructure = undefined;\n\n    const getFiles = async (dirHandle, path = dirHandle.name) => {\n      const dirs = [];\n      const files = [];\n      for await (const entry of dirHandle.values()) {\n        const nestedPath = `${path}/${entry.name}`;\n        if (entry.kind === \"file\") {\n          files.push(\n            entry.getFile().then((file) => {\n              file.directoryHandle = dirHandle;\n              file.handle = entry;\n              return Object.defineProperty(file, \"webkitRelativePath\", {\n                configurable: true,\n                enumerable: true,\n                get: () => nestedPath,\n              });\n            })\n          );\n        } else if (entry.kind === \"directory\") {\n          dirs.push(getFiles(entry, nestedPath));\n        }\n      }\n      return [\n        ...(await Promise.all(dirs)).flat(),\n        ...(await Promise.all(files)),\n      ];\n    };\n\n    try {\n      const handle = await showDirectoryPicker({\n        mode,\n      });\n      directoryStructure = getFiles(handle, undefined);\n    } catch (err) {\n      if (err.name !== \"AbortError\") {\n        console.error(err.name, err.message);\n      }\n    }\n    return directoryStructure;\n  }\n  // Fallback if the File System Access API is not supported.\n  return new Promise((resolve) => {\n    const input = document.createElement(''input'');\n    input.type = ''file'';\n    input.webkitdirectory = true;\n\n    input.addEventListener(''change'', () => {\n      let files = Array.from(input.files);\n      resolve(files);\n    });\n    if (''showPicker'' in HTMLInputElement.prototype) {\n      input.showPicker();\n    } else {\n      input.click();\n    }\n  });\n};\n\nbutton.addEventListener(''click'', async () => {\n  const filesInDirectory = await openDirectory();\n  if (!filesInDirectory) {\n    return;\n  }\n  Array.from(filesInDirectory).forEach((file) => (pre.textContent += `${file.name}\\n`));\n});\n"}', '{}', '{"original_path": "patterns/files/open-a-directory"}'), ('"open-one-or-multiple-files"', '"files"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nbutton {\n  margin: 1rem;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83d\udcc2</text></svg>\"\n    />\n    <title>How to open one or multiple files</title>\n  </head>\n  <body>\n    <h1>How to open one or multiple files</h1>\n    <button type=\"button\">Open file</button>\n    <button class=\"multiple\" type=\"button\">Open files</button>\n    <pre></pre>\n  </body>\n</html>\n", "demo.js": "const button = document.querySelector(''button'');\nconst buttonMultiple = document.querySelector(''button.multiple'');\nconst pre = document.querySelector(''pre'');\n\nconst openFileOrFiles = async (multiple = false) => {\n  // Feature detection. The API needs to be supported\n  // and the app not run in an iframe.\n  const supportsFileSystemAccess =\n    \"showOpenFilePicker\" in window &&\n    (() => {\n      try {\n        return window.self === window.top;\n      } catch {\n        return false;\n      }\n    })();\n\n  // If the File System Access API is supported\u2026\n  if (supportsFileSystemAccess) {\n    let fileOrFiles = undefined;\n    try {\n      // Show the file picker, optionally allowing multiple files.\n      fileOrFiles = await showOpenFilePicker({ multiple });\n      if (!multiple) {\n        // Only one file is requested.\n        fileOrFiles = fileOrFiles[0];\n      }\n    } catch (err) {\n      // Fail silently if the user has simply canceled the dialog.\n      if (err.name !== ''AbortError'') {\n        console.error(err.name, err.message);\n      }\n    }\n    return fileOrFiles;\n  }\n  // Fallback if the File System Access API is not supported.\n  return new Promise((resolve) => {\n    // Append a new `<input type=\"file\" multiple? />` and hide it.\n    const input = document.createElement(''input'');\n    input.style.display = ''none'';\n    input.type = ''file'';\n    document.body.append(input);\n    if (multiple) {\n      input.multiple = true;\n    }\n    // The `change` event fires when the user interacts with the dialog.\n    input.addEventListener(''change'', () => {\n      // Remove the `<input type=\"file\" multiple? />` again from the DOM.\n      input.remove();\n      // If no files were selected, return.\n      if (!input.files) {\n        return;\n      }\n      // Return all files or just one file.\n      resolve(multiple ? input.files : input.files[0]);\n    });\n    // Show the picker.\n    if (''showPicker'' in HTMLInputElement.prototype) {\n      input.showPicker();\n    } else {\n      input.click();\n    }\n  });\n};\n\nbutton.addEventListener(''click'', async () => {\n  const file = await openFileOrFiles();\n  if (!file) {\n    return;\n  }\n  pre.textContent += `${file.name}\\n`;\n});\n\nbuttonMultiple.addEventListener(''click'', async () => {\n  const files = await openFileOrFiles(true);\n  if (!files) {\n    return;\n  }\n  Array.from(files).forEach((file) => (pre.textContent += `${file.name}\\n`));\n});\n"}', '{}', '{"original_path": "patterns/files/open-one-or-multiple-files"}'), ('"receive-shared-files"', '"files"', '"vanilla"', '{"demo.css": "html {\n  box-sizing: border-box;\n  font-family: system-ui, sans-serif;\n  color-scheme: dark light;\n}\n\n*, *:before, *:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n}\n\nimg {\n  height: auto;\n  max-width: 100%;\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link rel=\"manifest\" href=\"manifest.json\" />\n    <title>How to receive shared files</title>\n    <link rel=\"stylesheet\" href=\"style.css\" />\n    <script>\n      if (''serviceWorker'' in navigator) {\n        window.addEventListener(''load'', async () => {\n          const registration = await navigator.serviceWorker.register(\n            ''sw.js'',\n          );\n          console.log(\n            ''Service worker registered for scope'',\n            registration.scope,\n          );\n        });\n      }\n    </script>\n    <script src=\"script.js\" type=\"module\"></script>\n  </head>\n  <body>\n    <h1>How to receive shared files</h1>\n    <p>Install the app. After the installation, try sharing an image to it from another app.\n  </body>\n</html>\n", "demo.js": "window.addEventListener(''load'', async () => {\n  if (location.search.includes(''share-target'')) {\n    const keys = await caches.keys();\n    const mediaCache = await caches.open(\n      keys.filter((key) => key.startsWith(''media''))[0],\n    );\n    const image = await mediaCache.match(''shared-image'');\n    if (image) {\n      const blob = await image.blob();\n      await mediaCache.delete(''shared-image'');\n      // Handle the shared file somehow.\n    }\n  }\n});\n", "demo.json": "{\n  \"name\": \"How to receive shared files\",\n  \"short_name\": \"Shared files\",\n  \"start_url\": \"../demo.html\",\n  \"id\": \"../demo.html\",\n  \"icons\": [\n    {\n      \"src\": \"../assets/favicon.png\",\n      \"type\": \"image/png\",\n      \"sizes\": \"512x512\"\n    },\n    {\n      \"src\": \"../assets/favicon.svg\",\n      \"type\": \"image/svg+xml\",\n      \"sizes\": \"any\"\n    }\n  ],\n  \"display\": \"standalone\",\n  \"share_target\": {\n    \"action\": \"../receive-files/\",\n    \"method\": \"POST\",\n    \"enctype\": \"multipart/form-data\",\n    \"params\": {\n      \"files\": [\n        {\n          \"name\": \"image\",\n          \"accept\": [\"image/jpeg\", \"image/png\", \"image/webp\", \"image/gif\"]\n        }\n      ]\n    }\n  }\n}", "demo.png": "\ufffdPNG\r\n\u001a\n\u0000\u0000\u0000\rIHDR\u0000\u0000\u0002\u0000\u0000\u0000\u0002\u0000\b\u0006\u0000\u0000\u0000\ufffdx\ufffd\ufffd\u0000\u0000\u0000\tpHYs\u0000\u0000;\u000e\u0000\u0000;\u000e\u0001\u0336\ufffd\ufffd\u0000\u0000\u0000\u0019tEXtSoftware\u0000www.inkscape.org\ufffd\ufffd<\u001a\u0000\u0000 \u0000IDATx\ufffd\ufffd\ufffdw|\u001c\u05797\ufffd\ufffd3e\ufffd\ufffde[\ufffd\u0018Y\ufffd-\ufffd\u0606\u0018\f\u0004[\ufffd\ufffd\ufffd\u000b.\ufffd\ufffd\ufffd\\\u0002$\ufffd\ufffdp\u0013\ufffd\ufffd\u0710\ufffd:\ufffd\ufffd\ufffdBH\ufffd\ufffd\ufffd`R\b\ufffd@\b\u0018C \t-!\u0010 \u0006Ls\ufffde\ufffd\u0576\ufffd9\ufffd\ufffd\ufffdJ\ufffd\ufffdvgf\ufffd\ufffd\u76cf\ufffd%\u035cyv\ufffd\ufffd\ufffd\ufffd)\ufffd\u0001\ufffd\u0010B\b!\ufffd\u0010B\b!\ufffd\u0010B\b!\ufffd\u0010B\b!\uf