eight=\"128\" opacity=\".3\"/><rect x=\"124\" width=\"4\" height=\"128\" opacity=\".3\"/><rect transform=\"matrix(-1.837e-16 1 -1 -1.837e-16 66 -62)\" x=\"62\" y=\"-58\" width=\"4\" height=\"120\" opacity=\".3\"/><rect transform=\"matrix(-1.837e-16 1 -1 -1.837e-16 190 62)\" x=\"62\" y=\"66\" width=\"4\" height=\"120\" opacity=\".3\"/></g></g></g></svg>\n"}', '{}', '{"original_path": "patterns/files/receive-shared-files"}'), ('"save-a-file"', '"files"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nimg {\n  max-width: 320px;\n  height: auto;\n}\n\nlabel,\nbutton,\ntextarea,\ninput,\nimg {\n  display: block;\n  margin-block: 1rem;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf89</text></svg>\"\n    />\n    <title>How to save a file</title>\n  </head>\n  <body>\n    <h1>How to save a file</h1>\n\n    <label\n      >Text to save\n      <textarea rows=\"3\">\nSome sample text for you to save. Feel free to edit this.</textarea\n      >\n    </label>\n    <label>File name <input class=\"text\" value=\"example.txt\" /></label>\n    <button class=\"text\" type=\"button\">Save text</button>\n\n    <label\n      >Image to save\n      <img\n        src=\"https://cdn.glitch.global/75170424-3d76-41d7-ae77-72d0efb0401b/AVIF%20Test%20picture%20(JPEG%20converted%20to%20AVIF%20with%20Convertio).avif?v=1658240752363\"\n        alt=\"Blue flower.\"\n        width=\"630\"\n        height=\"420\"\n    /></label>\n    <label>File name <input class=\"img\" value=\"example.avif\" /></label>\n    <button class=\"img\" type=\"button\">Save image</button>\n  </body>\n</html>\n", "demo.js": "const textarea = document.querySelector(''textarea'');\nconst textInput = document.querySelector(''input.text'');\nconst textButton = document.querySelector(''button.text'');\n\nconst img = document.querySelector(''img'');\nconst imgInput = document.querySelector(''input.img'');\nconst imgButton = document.querySelector(''button.img'');\n\nconst saveFile = async (blob, suggestedName) => {\n  // Feature detection. The API needs to be supported\n  // and the app not run in an iframe.\n  const supportsFileSystemAccess =\n    ''showSaveFilePicker'' in window &&\n    (() => {\n      try {\n        return window.self === window.top;\n      } catch {\n        return false;\n      }\n    })();\n  // If the File System Access API is supported\u2026\n  if (supportsFileSystemAccess) {\n    try {\n      // Show the file save dialog.\n      const handle = await showSaveFilePicker({\n        suggestedName,\n      });\n      // Write the blob to the file.\n      const writable = await handle.createWritable();\n      await writable.write(blob);\n      await writable.close();\n      return;\n    } catch (err) {\n      // Fail silently if the user has simply canceled the dialog.\n      if (err.name !== ''AbortError'') {\n        console.error(err.name, err.message);\n        return;\n      }\n    }\n  }\n  // Fallback if the File System Access API is not supported\u2026\n  // Create the blob URL.\n  const blobURL = URL.createObjectURL(blob);\n  // Create the `<a download>` element and append it invisibly.\n  const a = document.createElement(''a'');\n  a.href = blobURL;\n  a.download = suggestedName;\n  a.style.display = ''none'';\n  document.body.append(a);\n  // Click the element.\n  a.click();\n  // Revoke the blob URL and remove the element.\n  setTimeout(() => {\n    URL.revokeObjectURL(blobURL);\n    a.remove();\n  }, 1000);\n};\n\ntextButton.addEventListener(''click'', async () => {\n  const blob = new Blob([textarea.value], { type: ''text/plain'' });\n  await saveFile(blob, textInput.value);\n});\n\nimgButton.addEventListener(''click'', async () => {\n  const blob = await fetch(img.src).then((response) => response.blob());\n  await saveFile(blob, imgInput.value);\n});\n"}', '{}', '{"original_path": "patterns/files/save-a-file"}'), ('"share-files"', '"files"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nimg,\nvideo {\n  height: auto;\n  max-width: 100%;\n  display: block;\n}\n\nbutton {\n  margin: 1rem;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf89</text></svg>\"\n    />\n    <title></title>\n    <link rel=\"stylesheet\" href=\"style.css\" />\n    <script src=\"script.js\" type=\"module\"></script>\n  </head>\n  <body>\n    <h1>Share a file</h1>\n    <img\n      width=\"200\"\n      height=\"200\"\n      alt=\"A cat walking in the snow.\"\n      src=\"cat.png\"\n    />\n    <button type=button></button>\n  </body>\n</html>\n", "demo.js": "const button = document.querySelector(''button'');\nconst img =  document.querySelector(''img'');\n\nconst webShareSupported = ''canShare'' in navigator;\nbutton.textContent = webShareSupported ? ''Share'' : ''Download'';\n\nconst shareOrDownload = async (blob, fileName, title, text) => {\n  if (webShareSupported) {\n    const data = {\n      files: [\n        new File([blob], fileName, {\n          type: blob.type,\n        }),\n      ],\n      title,\n      text,\n    };\n    if (navigator.canShare(data)) {\n      try {\n        await navigator.share(data);\n      } catch (err) {\n        if (err.name !== ''AbortError'') {\n          console.error(err.name, err.message);\n        }\n      } finally {\n        return;\n      }\n    }\n  }\n  // Fallback\n  const a = document.createElement(''a'');\n  a.download = fileName;\n  a.style.display = ''none'';\n  a.href = URL.createObjectURL(blob);\n  a.addEventListener(''click'', () => {\n    setTimeout(() => {\n      URL.revokeObjectURL(a.href);\n      a.remove();\n    }, 1000)\n  });\n  document.body.append(a);\n  a.click();\n};\n\nbutton.addEventListener(''click'', async () => {\n  const blob = await fetch(img.src).then(res => res.blob());\n  await shareOrDownload(blob, ''cat.png'', ''Cat in the snow'', ''Getting cold feet\u2026'');\n});\n", "demo.png": "\ufffdPNG\r\n\u001a\n\u0000\u0000\u0000\rIHDR\u0000\u0000\u0000\ufffd\u0000\u0000\u0000\ufffd\b\u0002\u0000\u0000\u0000\":9\ufffd\u0000\u0000\f@iCCPICC Profile\u0000\u0000H\ufffd\ufffdW\u0007XS\ufffd\u0016\ufffd[R!\ufffd\u0004\u0010\ufffd\u0012z\u0013D\ufffd\u0004\ufffd\u0012B\u000b \ufffd\b6B\u0012 \ufffd\u0018\u0003A\u014e,*\ufffd\u0016TD\ufffd\ufffd\ufffd\ufffd(v@\uc21dE\ufffd\ufffd\u0142\ufffd\ufffd.\u0016\ufffd\u029b\u0014\ufffdu_\ufffd\ufffd|\ufffd\ufffd\ufffd\ufffd?g\ufffds\ufffd\u0719{\ufffd\u0000\ufffdq\ufffd''\ufffd\u481a\u0000\ufffd\ufffd!\u0001\ufffd1\ufffd)L\ufffd\u0013@\u0006(\ufffd\ufffd\ufffd\ufffd\ufffd\ufffdI\ufffd\ufffd\ufffd\u0011\u0000\ufffd\ufffd\ufffd\ufffd\ufffd\ufffdu\ufffd\ufffd\ufffd+\ufffdr\ufffd\u007f\ufffd\ufffd\u05e2%\u0010\ufffd\ufffd\u0001@\ufffd!N\u0013\ufffd\ufffds!\ufffd\u000f\u0000^\u0357H\ufffd\u0001 \ufffdy\ufffd)\ufffd\u00129\ufffd\u0015\ufffdHa\ufffd\u0010/\ufffd\ufffd\f%\ufffd\ufffd\ufffd4%\u07ad\ufffd\ufffd\ufffd\ufffd@\ufffd\n\u0000Y\ufffd\u01d3f\u0000@\ufffd\u0004yf\u0001?\u0003j\ufffd{!v\u0016\u000bDb\u00004\ufffd\u0010\ufffd\ufffd\ufffdN\u0012@\ufffd\n\ufffd-\ufffd\ufffd@,\ufffdg\ufffd\ufffd\ufffd\ufffd\ufffd7\u0374AM\u001e/c\u001